#!run
// workarea
import {get,set,assignDefault} from "@hoge1e3/global";
const id="df8914a3-fab5-4088-9dc9-eee5cec97c93";
export async function main(){
  const key="@acepad/worker";
  const id2w=init(key,()=>new Map());


  id2w.set("c",(id2w.get("c")||0)+10)
  return id2w.get("c");
}
export function init(key,f){
  assignDefault({
    [id]:{
      [key]:typeof f=="function"?f():f
    }
  });
  return get(id)[key];
}